# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import start_http_server, Summary

# Create a new metric for each unique user-path combination
user_path_metrics = {}

def track_request(user_id, session_id, request_path):
    # Create a unique label for this user-path combination
    label = f"{user_id}-{session_id}-{request_path}"

    # Check if the metric already exists
    if label not in user_path_metrics:
        # Create a new metric for this user-path combination
        user_path_metrics[label] = Summary(f"user_path_{label}", "Tracks HTTP requests by user, session, and path")

    # Increment the metric
    user_path_metrics[label].observe(1)

# Start the Prometheus HTTP server
start_http_server(8000)

# Example usage
track_request("123", "456", "/api/users")
track_request("123", "456", "/api/products")